import EspacioContacto from "./componentes/espacio-contacto/espacio-contacto";
import IniciarS from "./componentes/iniciar-s/iniciar-s";
import Registrarse from "./componentes/registrarse/registrarse";
import "./contacto.css"

function Contacto() {
    const iniciarsesion = true;
    const opacityiniciar = 0;
    const opacityregistrarse = 0;
    const filteriniciar = 0;
    const filterregistrarse = 0;


    if (iniciarsesion = true) {
        opacityiniciar = 1;
        filteriniciar = 0;

        opacityregistrarse = 0;
        filterregistrarse = 4;
    } else {
        opacityregistrarse = 1;
        filterregistrarse = 0;
        
        opacityiniciar = 0;
        filteriniciar = 4;
    }

    return (
        <div className="contacto-container">
            <EspacioContacto />
            <IniciarS opacity={opacityiniciar} filter={filteriniciar} />
            <Registrarse opacity={opacityregistrarse} filter={filterregistrarse} />
        </div>
    )
}

export default Contacto;
